import torch
import pandas as pd
import aiter
from aiter.tuned_gemm import asm_gemm, opus_gemm, triton_gemm, torch_gemm

device = "cuda"
dtype = torch.bfloat16

untuned = pd.read_csv("/app/gemma4_untuned_gemm.csv")
all_tuned = pd.read_csv("/app/gemma4_tuned_gemm_all.csv")

def timeit(fn, n_warmup=20, n_iter=100):
    for _ in range(n_warmup):
        fn()
    torch.cuda.synchronize()
    start = torch.cuda.Event(enable_timing=True)
    end = torch.cuda.Event(enable_timing=True)
    start.record()
    for _ in range(n_iter):
        fn()
    end.record()
    torch.cuda.synchronize()
    return start.elapsed_time(end) / n_iter * 1000  # us

rows = []
for _, urow in untuned.iterrows():
    M, N, K = int(urow["M"]), int(urow["N"]), int(urow["K"])
    A = torch.randn(M, K, dtype=dtype, device=device)
    B = torch.randn(N, K, dtype=dtype, device=device)

    candidates = {}

    # torch baseline
    def run_torch():
        return torch_gemm(A, B, 0, None, dtype, None, None, None, False, None)
    candidates["torch"] = (run_torch, {"libtype": "torch", "solidx": 0, "splitK": None, "kernelName": None})

    trow = all_tuned[(all_tuned.M == M) & (all_tuned.N == N) & (all_tuned.K == K)]
    if len(trow) == 1:
        t = trow.iloc[0]
        libtype = t["libtype"]
        if libtype == "asm":
            cfg = {"kernelName": t["kernelName"], "splitK": int(t["splitK"])}
            def run_asm(cfg=cfg):
                return asm_gemm(A, B, int(t["solidx"]), None, dtype, None, None, None, False, cfg)
            candidates["asm"] = (run_asm, {"libtype": "asm", "solidx": int(t["solidx"]), "splitK": int(t["splitK"]), "kernelName": t["kernelName"]})
        elif libtype == "opus":
            cfg = {"splitK": int(t["splitK"])}
            def run_opus(cfg=cfg, solidx=int(t["solidx"])):
                return opus_gemm(A, B, solidx, None, dtype, None, None, None, False, cfg)
            candidates["opus"] = (run_opus, {"libtype": "opus", "solidx": int(t["solidx"]), "splitK": int(t["splitK"]), "kernelName": t["kernelName"]})
        elif libtype == "triton":
            def run_triton():
                return triton_gemm(A, B, 0, None, dtype, None, None, None, False, None)
            candidates["triton"] = (run_triton, {"libtype": "triton", "solidx": 0, "splitK": None, "kernelName": "auto"})

    best_name = None
    best_us = None
    best_meta = None
    for name, (fn, meta) in candidates.items():
        us = timeit(fn)
        print(f"M={M} N={N} K={K} backend={name} us={us:.3f}")
        if best_us is None or us < best_us:
            best_us = us
            best_name = name
            best_meta = meta

    print(f" -> BEST for M={M} N={N} K={K}: {best_name} {best_us:.3f} us")
    rows.append({
        "gfx": "gfx950",
        "cu_num": 256,
        "M": M, "N": N, "K": K,
        "bias": False,
        "dtype": "torch.bfloat16",
        "outdtype": "torch.bfloat16",
        "scaleAB": False,
        "bpreshuffle": False,
        "libtype": best_meta["libtype"],
        "solidx": best_meta["solidx"],
        "splitK": best_meta["splitK"] if best_meta["splitK"] is not None else 0,
        "us": best_us,
        "kernelName": best_meta["kernelName"] if best_meta["kernelName"] is not None else "",
        "err_ratio": 0.0,
        "tflops": 0.0,
        "bw": 0.0,
    })

df = pd.DataFrame(rows)
df.to_csv("/app/gemma4_tuned_gemm_picked.csv", index=False)
print(df)
print("TOTAL_US (picked, from timeit):", df["us"].sum())

